// Map Google Sheets columns to scoring engine format
const row = $input.first().json;
return [{
  json: {
    company: row.Company || '',
    name: row.Name || '',
    role: row.Role || '',
    business_model: row['Business Model'] || '',
    offering_types: row['Offering Types'] || '',
    commerce_platform: row['Commerce Platform'] || '',
    catalog_interest: row['Catalog Features'] || '',
    pricing_capabilities: row['Pricing Capabilities'] || '',
    promotion_interest: row['Promotion Capabilities'] || '',
    willing_to_interview: row['Willing to Participate'] || 'No',
    email: row['Email Address'] || '',
    timestamp: new Date().toISOString()
  }
}];

const results = $input.first().json;
const significantChanges = results.capabilities.filter(c => c.score_delta && Math.abs(c.score_delta) > 0.5);
return [{ json: { has_changes: significantChanges.length > 0, changes: significantChanges, total: results.capabilities.length } }];

const data = $input.first().json;
const alerts = [];
for (const cap of data.capabilities || []) {
  if (cap.priority_changed) alerts.push(`⚠️ ${cap.name}: ${cap.old_priority} → ${cap.new_priority}`);
  if (Math.abs(cap.score_delta || 0) > 1.0) alerts.push(`📊 ${cap.name}: score ${cap.score_delta > 0 ? '+' : ''}${cap.score_delta.toFixed(2)}`);
}
return [{ json: { alerts, count: alerts.length, has_alerts: alerts.length > 0 } }];

const rows = $input.all();
const willing = rows.filter(r => r.json['Willing to Participate'] === 'Yes' && r.json['Email Address']);
return willing;
